import{_ as e,o as t,c as o,ae as r}from"./chunks/framework.0YMjjS-n.js";const n="/docs/screenshots/campaign-backstage-encounter.png",s="/docs/screenshots/campaign-backstage-encounter-outcome.png",i="/docs/screenshots/campaign-promo-hooks.png",c="/docs/screenshots/campaign-promo-outcome.png",h="/docs/screenshots/campaign-beginning.png",m="/docs/screenshots/campaign-tournament-bracket.png",p="/docs/screenshots/campaign-tag-team.png",l="/docs/screenshots/campaign-betrayal.png",u="/docs/screenshots/campaign-fighting-champion.png",g="/docs/screenshots/campaign-gang-warfare.png",d="/docs/screenshots/campaign-corporate-power-trip.png",f="/docs/screenshots/campaign-backstage-actions.png",b="/docs/screenshots/campaign-story-journal.png",x=JSON.parse('{"title":"Campaign","description":"","frontmatter":{},"headers":[],"relativePath":"guide/campaign.md","filePath":"guide/campaign.md"}'),y={name:"guide/campaign.md"};function k(_,a,q,T,P,v){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="campaign" tabindex="-1">Campaign <a class="header-anchor" href="#campaign" aria-label="Permalink to &quot;Campaign&quot;">​</a></h1><p>Welcome to the Campaign guide. This documentation is automatically generated from the latest game features.</p><h2 id="backstage-encounters" tabindex="-1">Backstage Encounters <a class="header-anchor" href="#backstage-encounters" aria-label="Permalink to &quot;Backstage Encounters&quot;">​</a></h2><p>Random encounters can occur when you visit the backstage area. These interactive dialogue segments force you to make choices that affect your alignment and momentum.</p><p><img src="'+n+'" alt="Backstage Encounters"></p><hr><h2 id="encounter-outcomes" tabindex="-1">Encounter Outcomes <a class="header-anchor" href="#encounter-outcomes" aria-label="Permalink to &quot;Encounter Outcomes&quot;">​</a></h2><p>Every choice in a backstage encounter has a narrative outcome and mechanical consequences, such as alignment shifts or bonuses for your next match.</p><p><img src="'+s+'" alt="Encounter Outcomes"></p><hr><h2 id="smart-promo-hooks" tabindex="-1">Smart Promo Hooks <a class="header-anchor" href="#smart-promo-hooks" aria-label="Permalink to &quot;Smart Promo Hooks&quot;">​</a></h2><p>The Smart Promo system uses AI to generate dynamic rhetorical hooks based on your wrestler&#39;s personality and current rivalries. Choose your strategy to connect with the audience or draw heat.</p><p><img src="'+i+'" alt="Smart Promo Hooks"></p><hr><h2 id="smart-promo-outcome" tabindex="-1">Smart Promo Outcome <a class="header-anchor" href="#smart-promo-outcome" aria-label="Permalink to &quot;Smart Promo Outcome&quot;">​</a></h2><p>Your choices have consequences. The crowd reaction, opponent retorts, and alignment shifts are all dynamically calculated, affecting your wrestler&#39;s momentum and reputation.</p><p><img src="'+c+'" alt="Smart Promo Outcome"></p><hr><h2 id="the-beginning" tabindex="-1">The Beginning <a class="header-anchor" href="#the-beginning" aria-label="Permalink to &quot;The Beginning&quot;">​</a></h2><p>Your journey starts here. Establish your reputation through backstage encounters and initial matches as you find your footing in All Time Wrestling.</p><p><img src="'+h+'" alt="The Beginning"></p><hr><h2 id="tournament-bracket" tabindex="-1">Tournament Bracket <a class="header-anchor" href="#tournament-bracket" aria-label="Permalink to &quot;Tournament Bracket&quot;">​</a></h2><p>The tournament chapter challenges you to climb the ranks in a single-elimination bracket. Win your matches to advance to the finals and claim the trophy.</p><p><img src="'+m+'" alt="Tournament Bracket"></p><hr><h2 id="tag-team-redemption" tabindex="-1">Tag Team Redemption <a class="header-anchor" href="#tag-team-redemption" aria-label="Permalink to &quot;Tag Team Redemption&quot;">​</a></h2><p>Experience the power of partnership. Find a compatible partner and dominate the tag team division while rebuilding your momentum.</p><p><img src="'+p+'" alt="Tag Team Redemption"></p><hr><h2 id="betrayal" tabindex="-1">Betrayal <a class="header-anchor" href="#betrayal" aria-label="Permalink to &quot;Betrayal&quot;">​</a></h2><p>Trust is a luxury you can no longer afford. Face the consequences of a broken alliance and seek retribution against your former partner.</p><p><img src="'+l+'" alt="Betrayal"></p><hr><h2 id="fighting-champion" tabindex="-1">Fighting Champion <a class="header-anchor" href="#fighting-champion" aria-label="Permalink to &quot;Fighting Champion&quot;">​</a></h2><p>As the Fighting Champion, you must defend your title against a series of challengers. Each defense increases your prestige but tests your stamina.</p><p><img src="'+u+'" alt="Fighting Champion"></p><hr><h2 id="gang-warfare" tabindex="-1">Gang Warfare <a class="header-anchor" href="#gang-warfare" aria-label="Permalink to &quot;Gang Warfare&quot;">​</a></h2><p>In Gang Warfare, you must navigate the dangerous world of factions. Build alliances or crush rivals as you fight for control of the locker room.</p><p><img src="'+g+'" alt="Gang Warfare"></p><hr><h2 id="corporate-power-trip" tabindex="-1">Corporate Power Trip <a class="header-anchor" href="#corporate-power-trip" aria-label="Permalink to &quot;Corporate Power Trip&quot;">​</a></h2><p>The authorities are against you. Survive impossible odds and unfair stipulations as you challenge the corrupt management&#39;s control.</p><p><img src="'+d+'" alt="Corporate Power Trip"></p><hr><h2 id="backstage-actions" tabindex="-1">Backstage Actions <a class="header-anchor" href="#backstage-actions" aria-label="Permalink to &quot;Backstage Actions&quot;">​</a></h2><p>Take daily actions to improve your stats, recover from injuries, or build hype for your next match. Choose wisely, as you have limited time each day.</p><p><img src="'+f+'" alt="Backstage Actions"></p><hr><h2 id="story-journal" tabindex="-1">Story Journal <a class="header-anchor" href="#story-journal" aria-label="Permalink to &quot;Story Journal&quot;">​</a></h2><p>Your AI-generated adventures are preserved in the Story Journal. Here you can review past storyline arcs and download them as JSON chapter files to share or preserve.</p><p><img src="'+b+'" alt="Story Journal"></p><hr>',54)])])}const B=e(y,[["render",k]]);export{x as __pageData,B as default};
